from agent import *from models.products import *def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.queue(Request('https://www.frogu.cz/'), process_frontpage, {})def process_frontpage(data, context, session):    strip_namespace(data)    cats = data.xpath('//ul[@id="gridmax-menu-primary-navigation"]/li/a')    for cat in cats:        name = cat.xpath('text()').string()        url = cat.xpath("@href").string()        session.queue(Request(url), process_revlist, dict(cat=name))def process_revlist(data, context, session):    strip_namespace(data)    revs = data.xpath('//div[contains(@class, "gridmax-posts-grid")]/div')    for rev in revs:        title = rev.xpath('.//h3[contains(@class, "post-title")]/a/text()').string()        url = rev.xpath('.//h3[contains(@class, "post-title")]/a/@href').string()        ssid = rev.xpath('@id').string().split('post-')[-1]        session.queue(Request(url), process_review, dict(context, title=title, url=url, ssid=ssid))    next_url = data.xpath('//a[@class="next page-numbers"]/@href').string()    if next_url:        session.queue(Request(next_url), process_revlist, dict(context))def process_review(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['title']    product.url = context['url']    product.category = context['cat']    product.ssid = context['ssid']    images = data.xpath('//div[@class="gridmax-box-inside"]//img')    for img in images:        img_alt = img.xpath('@alt').string()        img_url = img.xpath('@src').string()        if img_alt and img_url:            product.properties.append(ProductProperty(type="image", value={'src': img_url, 'alt': img_alt}))    review = Review()    review.title = product.name    review.url = product.url    review.ssid = product.ssid    review.type = 'pro'    date = data.xpath('//meta[@property="article:published_time"]/@content').string()    if date:        review.date = date.split('T')[0]    excerpt = data.xpath('//div[contains(@class, "entry-content")]/p[not(contains(., "Affiliate program"))]//text()').string(multiple=True)    if excerpt:        excerpt = excerpt.strip()        if excerpt:            review.add_property(type='excerpt', value=excerpt)            product.reviews.append(review)            session.emit(product)